const raw = $input.first().json?.body ?? $input.first().json;

const TEMPLATE_TO_ACTION = {
  welcome: "NEW_ACCOUNT",
  reset_password: "RESET_PASSWORD",
  otp_code: "OTP_CODE",
};

const ACTION_GATES = {
  RESET_PASSWORD: ["email"],
  NEW_ACCOUNT: ["email", "whatsapp"],
  USAGE_LIMIT: ["email", "whatsapp"],
  ACCOUNT_UPDATE: ["email", "whatsapp"],
  OTP_CODE: ["email", "whatsapp"],
};

let action = raw?.action
  ? String(raw.action)
      .trim()
      .toUpperCase()
      .replace(/-/g, "_")
  : "";
if (!action && raw?.template) {
  const key = String(raw.template).toLowerCase();
  action = TEMPLATE_TO_ACTION[key] || "";
}
if (!action || !ACTION_GATES[action]) {
  throw new Error("unknown or missing action (use RESET_PASSWORD, NEW_ACCOUNT, USAGE_LIMIT, ACCOUNT_UPDATE, OTP_CODE)");
}

const gateChannels = ACTION_GATES[action];
const email = raw?.email ? String(raw.email).trim() : "";
const phone = raw?.phone ? String(raw.phone).replace(/\D/g, "") : "";
const tenantId = raw.tenantId != null ? String(raw.tenantId).trim() : "";
const tenantDomain = raw.tenantDomain != null
  ? String(raw.tenantDomain).trim().toLowerCase()
  : "";
const data = raw?.data && typeof raw.data === "object" ? raw.data : {};

const sendEmail = gateChannels.includes("email") && Boolean(email);
const sendWhatsapp = gateChannels.includes("whatsapp") && Boolean(phone);

if (!sendEmail && !sendWhatsapp) {
  throw new Error(
    "no reachable channel for action " +
      action +
      ": provide email (required for email gate) and phone E.164 digits when WhatsApp is in gate"
  );
}

if (sendWhatsapp && !tenantDomain && !tenantId) {
  throw new Error(
    "tenantDomain (hostname) or legacy tenantId is required when WhatsApp is in the gate"
  );
}

const year = new Date().getFullYear();
const footer = `<p style="color:#9ca3af;font-size:12px;text-align:center;">gaqno &mdash; Plataforma de gestão para PMEs<br/>© ${year} gaqno.</p>`;
const portalUrl = "https://portal.gaqno.com.br";

let subject = "";
let html = "";
let whatsappText = "";

if (action === "NEW_ACCOUNT") {
  const name = data.name ? String(data.name) : "usuário";
  subject = "Bem-vindo à gaqno!";
  html = `<div style="font-family:'Segoe UI',Tahoma,sans-serif;max-width:560px;margin:0 auto;padding:40px 32px;background:#fff;"><div style="text-align:center;margin-bottom:40px;"><h1 style="color:#111827;font-size:28px;margin:0;">gaqno</h1></div><h2 style="color:#111827;font-size:22px;">Olá, ${name}!</h2><p style="color:#374151;font-size:16px;line-height:1.7;">Bem-vindo à <strong>gaqno</strong>.</p><p style="color:#374151;font-size:16px;">Sua conta foi criada com sucesso.</p><div style="text-align:center;margin:36px 0;"><a href="${portalUrl}/dashboard" style="display:inline-block;background:#111827;color:#fff;font-size:16px;font-weight:600;padding:14px 32px;border-radius:8px;text-decoration:none;">Acessar minha conta</a></div><hr style="border:none;border-top:1px solid #e5e7eb;margin:32px 0;"/>${footer}</div>`;
  whatsappText = `Olá, ${name}! Bem-vindo à gaqno. Acesse: ${portalUrl}/dashboard`;
} else if (action === "RESET_PASSWORD") {
  const name = data.name ? String(data.name) : "usuário";
  const resetUrl = data.resetUrl ? String(data.resetUrl) : "";
  if (!resetUrl) throw new Error("data.resetUrl is required for RESET_PASSWORD");
  subject = "Redefinição de senha – gaqno";
  html = `<div style="font-family:'Segoe UI',Tahoma,sans-serif;max-width:560px;margin:0 auto;padding:40px 32px;"><h1 style="color:#111827;text-align:center;">gaqno</h1><h2>Redefinir senha</h2><p>Olá, <strong>${name}</strong>.</p><p>Clique para criar uma nova senha:</p><div style="text-align:center;margin:36px 0;"><a href="${resetUrl}" style="display:inline-block;background:#111827;color:#fff;padding:14px 32px;border-radius:8px;text-decoration:none;">Redefinir minha senha</a></div><p style="color:#6b7280;font-size:14px;">Link expira em 30 minutos.</p><p style="color:#9ca3af;font-size:11px;word-break:break-all;">${resetUrl}</p><hr/>${footer}</div>`;
  whatsappText = "";
} else if (action === "OTP_CODE") {
  const code = data.code ? String(data.code) : "";
  if (!code) throw new Error("data.code is required for OTP_CODE");
  subject = "Seu código de verificação gaqno";
  html = `<div style="font-family:'Segoe UI',sans-serif;max-width:480px;margin:0 auto;padding:32px;"><h1 style="color:#111827;text-align:center;">gaqno</h1><p>Use o código:</p><div style="text-align:center;margin:32px 0;"><span style="font-size:36px;font-weight:700;letter-spacing:8px;background:#f3f4f6;padding:16px 32px;border-radius:12px;">${code}</span></div><p style="color:#6b7280;font-size:14px;">Expira em 5 minutos.</p>${footer}</div>`;
  whatsappText = `*${code}* é seu código gaqno. Expira em 5 minutos. Não compartilhe.`;
} else if (action === "USAGE_LIMIT") {
  const name = data.name ? String(data.name) : "usuário";
  const msg = data.message
    ? String(data.message)
    : data.detail
      ? String(data.detail)
      : "";
  if (!msg) throw new Error("data.message or data.detail is required for USAGE_LIMIT");
  const resource = data.resource ? String(data.resource) : "plano";
  subject = "Limite de uso – gaqno";
  html = `<div style="font-family:'Segoe UI',sans-serif;max-width:560px;margin:0 auto;padding:32px;"><h2 style="color:#111827;">Limite de uso</h2><p style="color:#374151;">Olá, <strong>${name}</strong>.</p><p style="color:#374151;white-space:pre-wrap;">${msg.replace(/</g, "&lt;").replace(/>/g, "&gt;")}</p><p style="color:#6b7280;font-size:14px;">Recurso: ${resource.replace(/</g, "&lt;")}</p><p><a href="${portalUrl}/dashboard">${portalUrl}/dashboard</a></p><hr/>${footer}</div>`;
  whatsappText = `*Limite de uso gaqno*\nOlá, ${name}. ${msg}`;
} else if (action === "ACCOUNT_UPDATE") {
  const name = data.name ? String(data.name) : "usuário";
  const msg = data.message
    ? String(data.message)
    : data.changeSummary
      ? String(data.changeSummary)
      : "";
  if (!msg) throw new Error("data.message or data.changeSummary is required for ACCOUNT_UPDATE");
  subject = "Atualização na sua conta – gaqno";
  html = `<div style="font-family:'Segoe UI',sans-serif;max-width:560px;margin:0 auto;padding:32px;"><h2 style="color:#111827;">Conta atualizada</h2><p style="color:#374151;">Olá, <strong>${name}</strong>.</p><p style="color:#374151;white-space:pre-wrap;">${msg.replace(/</g, "&lt;").replace(/>/g, "&gt;")}</p><p><a href="${portalUrl}/dashboard">Abrir o painel</a></p><hr/>${footer}</div>`;
  whatsappText = `*Conta gaqno atualizada*\nOlá, ${name}. ${msg}`;
}

return [
  {
    json: {
      sendEmail,
      sendWhatsapp,
      email,
      phone,
      tenantId,
      tenantDomain,
      subject,
      html,
      whatsappText,
    },
  },
];
